import React from 'react';

import TextLine from './text-line';

import classes from './text-display.module.css';

const countVowels = (text) => {
    const regExp = new RegExp('[aàáâãäåæāăąeèéêëēĕėęěiìíîïĩīĭįıoðòóôõöøōŏőœuùúûüũūŭůűųyýÿŷаеёиоуыэюяѐєіїѝўӑӓӕӗәӛӣӥӧөӫӭӯӱӳӹαεηιουω]', 'gi');

    return text.match(regExp);
};

const countWords = (text) => {
    const words = text.split(' ');
    const filteredWords = words.filter((word) => {
        if(word.length > 0 && word != ' ') {
            return word;
        }
    });

    return filteredWords;
};

const TextDisplay = (props) => {
    const textLines = props.texts.map((text) => {
        const vowels = countVowels(text.line);
        const words = countWords(text.line);
        return <TextLine line={text.line} key={text.id} amountVowels={vowels.length} amountWords={words.length}/>
    });

    return (
        <div className={classes['text-display']}>
            {textLines}
        </div>
    );
};

export default TextDisplay;