import React, {useState, useEffect} from 'react';

import classes from './input-area.module.css';

// This function takes user's input data and return an object whith array of valid indexes and array of errors.
const validation = (textArray) => {
    let inputText = [];
    let errorText = [];

    textArray.forEach((text) => {
        const i = text.trim();

        if (i.length > 0) {
            if (isNaN(+i) || +i > 20 || +i < 1) {
                errorText.push(i);
            } else {
                inputText.push(+i);
            }
        }
    });

    return {
        input: inputText,
        errors: errorText,
    };
};

const InputArea = (props) => {
    const [inputValue, setInputValue] = useState('');
    const [isValid, setIsValid] = useState(null);
    const [inputArray, setInputArray] = useState([]);
    const [errorArray, setErrorArray] = useState('');

    let errorMessage = '';
    let textColor = '';
    let buttonClass = '';

    // useEffect hook is used here to validate data after user's end of input instead of checking every change.
    useEffect(() => {
        const regEx = new RegExp('[,;]');
        const identifier = setTimeout(() => {
            if(inputValue.length > 0) {
                const arr = inputValue.split(regEx);
                const textObj = validation(arr);

                setInputArray(textObj.input);
                setErrorArray(textObj.errors.join(', '));

                if (textObj.input.length > 0 && textObj.errors.length === 0) {
                    setIsValid(true);
                } else {
                    setIsValid(false);
                }
            } else {
                setIsValid(null); // null - default isValid condition when input is empty.
                setInputArray([]);
                setErrorArray('');
            }
        }, 500);

        return () => {
            clearTimeout(identifier);
        };

    }, [inputValue]);

    const inputChangeHandler = (event) => {
        setInputValue(event.target.value);
    };

    const onSubmitHandler = (event) => {
        event.preventDefault();
        if (isValid === false || isValid === null) { // submit button is unactive untill isValid === true
            return;
        }
        props.submitIndexes(inputArray); // data is provided up in app component
        setInputValue('');
    };

    if (isValid === true) {
        errorMessage = 'Data is correct';
        textColor = 'green';
        buttonClass = 'active';
    }
    if (isValid === false) {
        errorMessage = 'Incorrect data: ';
        textColor = 'red';
        buttonClass = '';
    }
    if (isValid === null) {
        errorMessage = '';
        textColor = '';
        buttonClass = '';
    }

    return (
        <div className={classes['input-area']}>
            <form onSubmit={onSubmitHandler}>
                <input type='text' value={inputValue} onChange={inputChangeHandler}/>
                <button className={classes[buttonClass]}>SUBMIT</button>
            </form>
            <div className={`${classes.error} ${classes[textColor]}`}>{errorMessage}{errorArray}</div>
        </div>
    );
};

export default InputArea;