import React from 'react';

import classes from './text-line.module.css';

const TextLine = (props) => {
    return (
        <div className={classes['text-line']}>
            <div className={classes.text}>{props.line}</div>
            <div className={classes.number}>{props.amountVowels}</div>
            <div className={classes.number}>{props.amountWords}</div>
        </div>
    );
};

export default TextLine;