import React, {useState} from 'react';

import InputArea from './components/input/input-area';
import TextDisplay from './components/text/text-display';
import ErrorMessage from './components/error/error-message';

const App = () => {
  const [texts, setTexts] = useState([]);
  const [serverStatus, setServerStatus] = useState(200);

  const errors = {
    '400': 'Bad Request',
    '403': 'Forbidden',
    '404': 'Data from your request is not found',
    '418': 'Unfortunately, server is a teapot now. Please return later when it transforms in something different.',
    '503': 'Service Unavailable',
    '504': 'Gateway Timeout',
  }

  let content;
  let message;

  async function textHandler(id) {
    const res = await fetch(`https://tmgwebtest.azurewebsites.net/api/textstrings/${id}`, {
        headers: {
            'TMG-Api-Key': '0J/RgNC40LLQtdGC0LjQutC4IQ==',
        },
    });

    await setServerStatus(res.status);

    const text = await res.json();

    await setTexts((prev) => {
      return [...prev, {line: text.text, id: id}]
    });
  }

  const submitIndexes = (array) => {
    setTexts([]);
    setServerStatus(200);
    array.forEach((id) => {
      if (!serverStatus === 200) {
        return;
      }
      textHandler(id);
    })
  };

  if (serverStatus === 200) {
    content = <TextDisplay texts = {texts}/>;
  } else {
    if (Object.keys(errors).includes(serverStatus.toString())) {
      message = errors[serverStatus.toString()];
    } else {
      message = 'Unknown error';
    }
    content = <ErrorMessage number={serverStatus} message={message}/>;
  }

  return (
    <>
      <InputArea submitIndexes = {submitIndexes}/>
      {content}
    </>
  );
};

export default App;